import{_ as e,o as r,c as t,ag as i}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/1.jpg.DBs3SK40.jpg",l="/kaiping-reports/assets/2.jpg._vUWMe5R.jpg",s="/kaiping-reports/assets/3.jpg._KdkWxSx.jpg",p="/kaiping-reports/assets/4.jpg.sKiOoR9d.jpg",h="/kaiping-reports/assets/5.jpg.pbUvDLyE.jpg",n="/kaiping-reports/assets/6.jpg.DA3PxeOA.jpg",_="/kaiping-reports/assets/7.jpg.EQd9dZ7p.jpg",c="/kaiping-reports/assets/8.jpg.B-P8GeCM.jpg",d="/kaiping-reports/assets/9.jpg.B9SXmrXW.jpg",g="/kaiping-reports/assets/10.jpg.BTEerj-E.jpg",P=JSON.parse('{"title":"开平市立园装饰符号与文化表达调研报告","description":"","frontmatter":{},"headers":[],"relativePath":"reports/唐佳馨/唐佳馨-开平市立园装饰符号与文化表达调研报告.md","filePath":"reports/唐佳馨/唐佳馨-开平市立园装饰符号与文化表达调研报告.md"}'),m={name:"reports/唐佳馨/唐佳馨-开平市立园装饰符号与文化表达调研报告.md"};function u(q,a,b,j,k,f){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="开平市立园装饰符号与文化表达调研报告" tabindex="-1">开平市立园装饰符号与文化表达调研报告 <a class="header-anchor" href="#开平市立园装饰符号与文化表达调研报告" aria-label="Permalink to &quot;开平市立园装饰符号与文化表达调研报告&quot;">​</a></h1><p><strong>作者：唐佳馨</strong></p><h2 id="一、引言-立园装饰——华侨文化的视觉符号系统" tabindex="-1">一、引言：立园装饰——华侨文化的视觉符号系统 <a class="header-anchor" href="#一、引言-立园装饰——华侨文化的视觉符号系统" aria-label="Permalink to &quot;一、引言：立园装饰——华侨文化的视觉符号系统&quot;">​</a></h2><p>立园位于广东省江门市开平市塘口镇，始建于1926年，由旅美华侨谢维立先生历时十年营造，是集岭南园林艺术与西方建筑风格于一体的私家园林。2007年，开平碉楼与村落被列入世界文化遗产名录，立园作为其中的杰出代表，其装饰符号所承载的文化杂交特征成为研究近代华侨建筑的重要样本。</p><p>我们小组的调研聚焦于立园的装饰符号与文化表达，聚焦雕刻、灰塑、柱式、拱券、匾额、色彩、材料工艺等具体要素，以本专业视角，结合建筑史与文化遗产保护理论，系统梳理立园装饰的中西融合特征、题材类型、空间分布、工艺逻辑与文化内涵。调研采用装饰元素分类采集+符号标注+位置记录的方法，对门楼、主体建筑、园林景观、细部节点进行全覆盖记录，明确装饰位置、题材、风格、材料与文化指向，回答三个核心问题：立园装饰如何实现西方形式与本土手法的创造性融合；装饰符号系统承载了怎样的文化表达与身份建构；在博物馆化保护模式下，立园装饰的遗产价值如何被认知、保护与当代转译。</p><h2 id="二、立园装饰符号的中西融合形态与构成逻辑" tabindex="-1">二、立园装饰符号的中西融合形态与构成逻辑 <a class="header-anchor" href="#二、立园装饰符号的中西融合形态与构成逻辑" aria-label="Permalink to &quot;二、立园装饰符号的中西融合形态与构成逻辑&quot;">​</a></h2><p>立园的装饰很明显是中式和西式结合、分层搭配的：主体结构学西方，外表装饰保留中国传统；外形借鉴国外样式，制作工艺用岭南本地手法。这种设计是为了用上现代先进技术，同时守住自己的文化根脉，也是20世纪初岭南华侨建筑最常见的装饰做法。</p><h3 id="_2-1-结构装饰-西式构件与中式表皮的并置" tabindex="-1">2.1 结构装饰：西式构件与中式表皮的并置 <a class="header-anchor" href="#_2-1-结构装饰-西式构件与中式表皮的并置" aria-label="Permalink to &quot;2.1 结构装饰：西式构件与中式表皮的并置&quot;">​</a></h3><p>立园采用内部西式结构、外部中式表皮的设计，形成内新外旧、内西外中的鲜明特点。结构上运用西方古典柱式、拱券、山花等元素，搭配钢筋混凝土，坚固现代，体现华侨对西方技术与审美的吸收。外观上保留青瓦坡顶、青砖墙面、传统屋脊等中式特征，符合岭南民居实用透气的特点。（图1、图2）这种融合既让建筑更坚固安全，又坚守中式文化符号，展现出华侨既拥有海外视野、又心系故土根脉的双重情怀。</p><p><img src="'+o+'" alt="1.jpg"><img src="'+l+'" alt="2.jpg"></p><h3 id="_2-2-细部装饰-西式构件与中式工艺的结合" tabindex="-1">2.2 细部装饰：西式构件与中式工艺的结合 <a class="header-anchor" href="#_2-2-细部装饰-西式构件与中式工艺的结合" aria-label="Permalink to &quot;2.2 细部装饰：西式构件与中式工艺的结合&quot;">​</a></h3><p>立园的细节装饰最能体现外形学西方、工艺守本土的特点。它直接借鉴了西方的造型与结构，但材料、做法和装饰内容都完全本土化，做到样子像西方、精神是中国。</p><p>最常见的组合是：西式拱券搭配中式灰塑、西式线条搭配中式雕刻、西式柱头搭配中式匾额对联。立园的窗、门、走廊大量使用西式弧形拱券，但拱券边缘和内部都用岭南灰塑装饰，题材换成花鸟、瑞兽、吉祥文字，靠手工塑形、多层彩绘，耐用又适合南方气候。西式线条被简化处理，结合砖雕、木刻加入蝙蝠、祥云、梅兰竹菊等传统图案；西式柱子旁边还配上楹联匾额，用&quot;立地顶天无愧祖先薪火，身居海外常怀故国山河&quot;直接表达家国情怀。</p><p>从建筑历史来看，立园并不是盲目照搬西方装饰，而是结合岭南工匠的技术、本地材料和审美习惯做了本土化改造。西方装饰多用石材雕刻、模具批量生产，讲究几何精准；而立园以灰塑、砖雕、木刻、水泥塑作为主，以手工制作为主，更看重吉祥寓意和地域适应性。这种先学习西方形式、再用本土手法重新创作的方式，既吸收了西方的现代审美与技术，又牢牢保留了岭南传统工艺的根基。（图3）</p><p><img src="'+s+'" alt="3.jpg"></p><h2 id="三、立园装饰符号分类采集与记录" tabindex="-1">三、立园装饰符号分类采集与记录 <a class="header-anchor" href="#三、立园装饰符号分类采集与记录" aria-label="Permalink to &quot;三、立园装饰符号分类采集与记录&quot;">​</a></h2><h3 id="_3-1-按装饰位置分类记录" tabindex="-1">3.1 按装饰位置分类记录 <a class="header-anchor" href="#_3-1-按装饰位置分类记录" aria-label="Permalink to &quot;3.1 按装饰位置分类记录&quot;">​</a></h3><p>立园装饰重点突出、层次清晰，与建筑功能和视觉路线高度匹配。</p><ol><li>入口与门楼：视觉核心，装饰最密集，用以彰显家族身份与实力。</li><li>建筑立面：装饰主要区域，用西式构件定整体秩序，中式纹样补细节美感。</li><li>屋顶与屋脊：以青瓦为底，装饰简洁雅致，突出中式屋顶的造型特点。</li><li>园林景观：栏杆、花台、小品等采用中西结合设计，风格统一协调。（图4）</li><li>室内过渡空间：以木刻、灰塑、题字为主，多用家训与吉祥语，营造文化氛围。（图5）</li></ol><p><img src="'+p+'" alt="4.jpg"><img src="'+h+'" alt="5.jpg"></p><h3 id="_3-2-按装饰题材分类记录" tabindex="-1">3.2 按装饰题材分类记录 <a class="header-anchor" href="#_3-2-按装饰题材分类记录" aria-label="Permalink to &quot;3.2 按装饰题材分类记录&quot;">​</a></h3><p>立园装饰题材分为中式传统、西式装饰、中西合璧三类。</p><ol><li>中式传统题材：以吉祥动植物（图6）、匾额楹联、山水故事为主，表达家国情怀与吉祥寓意。</li><li>西式装饰题材：以卷草、几何纹等为主，强调现代感与形式美感。（图7）</li><li>中西合璧题材：西式构图搭配中式内容，造型与文化内涵兼顾。</li></ol><p><img src="'+n+'" alt="6.jpg"><img src="'+_+'" alt="7.jpg"></p><h3 id="_3-3-按风格特征记录" tabindex="-1">3.3 按风格特征记录 <a class="header-anchor" href="#_3-3-按风格特征记录" aria-label="Permalink to &quot;3.3 按风格特征记录&quot;">​</a></h3><ol><li>西式风格：古典、巴洛克、简约几何，规整对称、现代感强。（图8）</li><li>中式风格：岭南传统，重寓意、手工制作、亲切自然。（图9）</li><li>融合风格：西式结构为骨架，中式文化为内涵，整体协调统一。</li></ol><p><img src="'+c+'" alt="8.jpg"><img src="'+d+'" alt="9.jpg"></p><h2 id="四、立园装饰的材料、色彩与工艺表达" tabindex="-1">四、立园装饰的材料、色彩与工艺表达 <a class="header-anchor" href="#四、立园装饰的材料、色彩与工艺表达" aria-label="Permalink to &quot;四、立园装饰的材料、色彩与工艺表达&quot;">​</a></h2><h3 id="_4-1-材料与质感" tabindex="-1">4.1 材料与质感 <a class="header-anchor" href="#_4-1-材料与质感" aria-label="Permalink to &quot;4.1 材料与质感&quot;">​</a></h3><p>立园选材以本土材料为主、现代材料为辅，兼顾实用、经济与美观。主体用青砖与混凝土，做到外观传统、结构现代；装饰多用灰塑、砖雕、木刻与水泥预制件，适配岭南气候且施工高效。</p><p>它没有用西方昂贵石材，而是外形学西方、材料用本土，既节约成本，也体现出华侨务实的态度与本土文化自信。</p><h3 id="_4-2-色彩运用" tabindex="-1">4.2 色彩运用 <a class="header-anchor" href="#_4-2-色彩运用" aria-label="Permalink to &quot;4.2 色彩运用&quot;">​</a></h3><p>立园的色彩搭配低调稳重、重点鲜明。整体以青砖灰、水泥灰、原木色为主，看起来朴素大气；装饰部分只用红、绿、蓝、金等彩绘，以及匾额常用的黑底金字、红底金字来突出重点。（图10）它不追求花哨抢眼，而是用色彩突出装饰符号，清晰传递文化内涵。</p><p><img src="'+g+'" alt="10.jpg"></p><h3 id="_4-3-工艺特征" tabindex="-1">4.3 工艺特征 <a class="header-anchor" href="#_4-3-工艺特征" aria-label="Permalink to &quot;4.3 工艺特征&quot;">​</a></h3><p>立园的工艺充分体现了外形借鉴西方、手法坚守本土的特点，西方工艺注重标准、规整与几何精准，而中式工艺更强调手工制作、灵活造型和吉祥寓意；立园一方面借鉴西方的构件样式与模具技术，简化线条降低施工难度，另一方面由本地匠人用传统手工完成制作，并融入吉祥题材与岭南地方技法，最终形成了独一无二的装饰工艺体系。</p><h2 id="五、立园装饰符号的文化表达与身份建构" tabindex="-1">五、立园装饰符号的文化表达与身份建构 <a class="header-anchor" href="#五、立园装饰符号的文化表达与身份建构" aria-label="Permalink to &quot;五、立园装饰符号的文化表达与身份建构&quot;">​</a></h2><p>立园的装饰，本质上是华侨用来展示财富、表达家国情怀、体现中西双重文化身份的视觉语言。</p><p>在20世纪30年代的侨乡，装饰的精美程度直接代表家族的经济实力与社会地位。西式装饰体现主人的海外见识，繁复工艺彰显财力，成为无声的身份名片。同时，立园的匾额、吉祥图案与中式外观，处处流露着华侨对故土的思念与文化认同，让建筑成为承载乡愁的精神家园。整体装饰既体现华侨主动接受西方现代技术与审美，又坚守中国传统文化内核，展现出既面向世界、又不忘本土的自信与平衡。</p><h2 id="六、基于建筑史与遗产保护的批判性思考" tabindex="-1">六、基于建筑史与遗产保护的批判性思考 <a class="header-anchor" href="#六、基于建筑史与遗产保护的批判性思考" aria-label="Permalink to &quot;六、基于建筑史与遗产保护的批判性思考&quot;">​</a></h2><p>立园装饰是20世纪初岭南华侨建筑的典型代表，记录了中西建筑文化交流历程，具有重要的物质与非物质遗产价值。目前博物馆化保护完整保留了历史原貌，但装饰脱离生活场景，缺乏活态传承。对环境设计而言，应转译其设计逻辑与文化内核而非照搬符号。遗产保护需平衡专家、文化、社区三方需求，兼顾原真保留、活态活化与当代转译，让传统装饰持续发挥价值。</p><h2 id="七、结论" tabindex="-1">七、结论 <a class="header-anchor" href="#七、结论" aria-label="Permalink to &quot;七、结论&quot;">​</a></h2><p>开平立园的装饰是岭南华侨建筑中西融合的典范，采用外中内西、本土工艺的做法，展现了华侨的审美与家国情怀。</p><p>调研发现，立园装饰体系完整、逻辑清晰，具有重要的建筑史与文化遗产价值。当前博物馆化保护保留了原貌，未来还需要进一步活化利用。</p><p>对环境设计专业而言，立园告诉我们：传统与现代融合要学逻辑、不抄符号；做设计重内涵、不重形式；保护遗产要重传承、不简单封存。它的设计智慧，能持续为当代设计提供灵感。</p><h2 id="八、附录" tabindex="-1">八、附录 <a class="header-anchor" href="#八、附录" aria-label="Permalink to &quot;八、附录&quot;">​</a></h2><h3 id="_8-2-参考文献" tabindex="-1">8.2 参考文献 <a class="header-anchor" href="#_8-2-参考文献" aria-label="Permalink to &quot;8.2 参考文献&quot;">​</a></h3><ol><li>《开平碉楼》，广东省文物考古研究所，文物出版社，2007</li><li>《华侨建筑文化研究》，华侨大学建筑学院，中国建筑工业出版社，2010</li><li>《文化遗产保护的理论与实践》，同济大学建筑与城市规划学院，同济大学出版社，2015</li><li>《开平碉楼村落保护与利用研究》，华南理工大学出版社，2018</li><li>《岭南建筑装饰艺术》，广东科技出版社，2020</li></ol>',48)])])}const S=e(m,[["render",u]]);export{P as __pageData,S as default};
